import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { FaArrowLeft, FaBook, FaFileAlt, FaClock, FaStar, FaSearch } from 'react-icons/fa';
import { getSubjectsForSemester } from '../services/api';
import { coursesData, getSubjects } from '../data/coursesData';

const SubjectSelection = () => {
  const { courseId, yearId, semId } = useParams();
  const navigate = useNavigate();
  const [subjects, setSubjects] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);

  // Mock courses data
  const coursesData = {
    1: { name: "B.Tech", icon: "💻" },
    2: { name: "BCA", icon: "📱" },
    3: { name: "BBA", icon: "📊" },
    4: { name: "MBA", icon: "🎓" },
    5: { name: "MCA", icon: "💼" }
  };

  // // Mock subjects data based on semester
  // const subjectsBySemester = {
  //   1: [
  //     { id: 1, name: 'Mathematics-I', code: 'MATH101', credits: 4, materials: 12, rating: 4.5 },
  //     { id: 2, name: 'Physics', code: 'PHY101', credits: 4, materials: 15, rating: 4.2 },
  //     { id: 3, name: 'Chemistry', code: 'CHE101', credits: 4, materials: 10, rating: 4.3 },
  //     { id: 4, name: 'Programming in C', code: 'CSE101', credits: 3, materials: 20, rating: 4.8 },
  //     { id: 5, name: 'English', code: 'ENG101', credits: 2, materials: 8, rating: 4.0 },
  //   ],
  //   2: [
  //     { id: 6, name: 'Mathematics-II', code: 'MATH102', credits: 4, materials: 14, rating: 4.4 },
  //     { id: 7, name: 'Data Structures', code: 'CSE201', credits: 4, materials: 25, rating: 4.9 },
  //     { id: 8, name: 'Digital Electronics', code: 'ECE101', credits: 4, materials: 18, rating: 4.6 },
  //     { id: 9, name: 'Discrete Mathematics', code: 'MATH201', credits: 3, materials: 12, rating: 4.3 },
  //   ],
  //   3: [
  //     { id: 10, name: 'Algorithms', code: 'CSE301', credits: 4, materials: 22, rating: 4.7 },
  //     { id: 11, name: 'Database Management', code: 'CSE302', credits: 4, materials: 20, rating: 4.8 },
  //     { id: 12, name: 'Computer Networks', code: 'CSE303', credits: 4, materials: 18, rating: 4.5 },
  //     { id: 13, name: 'Operating Systems', code: 'CSE304', credits: 4, materials: 16, rating: 4.6 },
  //   ],
  //   4: [
  //     { id: 14, name: 'Software Engineering', code: 'CSE401', credits: 4, materials: 15, rating: 4.4 },
  //     { id: 15, name: 'Web Technologies', code: 'CSE402', credits: 3, materials: 22, rating: 4.9 },
  //     { id: 16, name: 'Machine Learning', code: 'CSE403', credits: 4, materials: 20, rating: 4.8 },
  //     { id: 17, name: 'Project Work', code: 'CSE404', credits: 5, materials: 10, rating: 4.2 },
  //   ]
  // };

  useEffect(() => {
    fetchSubjects();
  }, [semId]);

  const fetchSubjects = async () => {
    try {
      // Simulate API call
      setTimeout(() => {
        const semSubjects = subjectsBySemester[semId] || subjectsBySemester[1];
        setSubjects(semSubjects);
        setLoading(false);
      }, 800);
    } catch (error) {
      console.error('Error fetching subjects:', error);
      setLoading(false);
    }
  };

  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}`);
  };

  const handleSubjectClick = (subjectId) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}/subject/${subjectId}`);
  };

  const filteredSubjects = subjects.filter(subject =>
    subject.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    subject.code.toLowerCase().includes(searchQuery.toLowerCase())
  );

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingSpinner}></div>
        <p>Loading subjects for Semester {semId}...</p>
      </div>
    );
  }

  const course = coursesData[courseId] || { name: 'Course', icon: '📚' };

  return (
    <div style={styles.container}>
      {/* Header with Back Button */}
      <div style={styles.header}>
        <button onClick={handleBack} style={styles.backButton}>
          <FaArrowLeft /> Back to Semesters
        </button>
        
        <div style={styles.pageHeader}>
          <div style={styles.courseSemesterInfo}>
            <h1 style={styles.title}>
              <span style={styles.courseIcon}>{course.icon}</span>
              {course.name} - Year {yearId}
            </h1>
            <p style={styles.subtitle}>Semester {semId} - Select Subject</p>
          </div>
        </div>
      </div>

      {/* Search Bar */}
      <div style={styles.searchSection}>
        <div style={styles.searchContainer}>
          <FaSearch style={styles.searchIcon} />
          <input
            type="text"
            placeholder="Search subjects by name or code..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            style={styles.searchInput}
          />
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              style={styles.clearButton}
            >
              Clear
            </button>
          )}
        </div>
        <p style={styles.searchInfo}>
          Found {filteredSubjects.length} subject{filteredSubjects.length !== 1 ? 's' : ''}
        </p>
      </div>

      {/* Subjects Grid */}
      <div style={styles.subjectsGrid}>
        {filteredSubjects.length === 0 ? (
          <div style={styles.emptyState}>
            <div style={styles.emptyIcon}>🔍</div>
            <h3>No subjects found!</h3>
            <p>Try a different search term</p>
          </div>
        ) : (
          filteredSubjects.map(subject => (
            <div
              key={subject.id}
              style={styles.subjectCard}
              onClick={() => handleSubjectClick(subject.id)}
            >
              <div style={styles.subjectHeader}>
                <div style={styles.subjectIcon}>
                  <FaBook size={24} />
                </div>
                <div style={styles.subjectCodeBadge}>
                  {subject.code}
                </div>
              </div>

              <h3 style={styles.subjectName}>{subject.name}</h3>
              <p style={styles.subjectCredits}>{subject.credits} Credits</p>

              <div style={styles.subjectStats}>
                <span style={styles.statItem}>
                  <FaFileAlt /> {subject.materials} Materials
                </span>
                <span style={styles.statItem}>
                  <FaStar /> {subject.rating}/5
                </span>
              </div>

              <div style={styles.materialTypes}>
                <span style={styles.materialBadge}>Syllabus</span>
                <span style={styles.materialBadge}>Notes</span>
                <span style={styles.materialBadge}>PYQs</span>
                <span style={styles.materialBadge}>Lab Files</span>
              </div>

              <button style={styles.viewMaterialsButton}>
                View Study Materials →
              </button>
            </div>
          ))
        )}
      </div>

      {/* Semester Info */}
      <div style={styles.semesterInfo}>
        <h3>📚 Semester {semId} Information</h3>
        <div style={styles.infoGrid}>
          <div style={styles.infoCard}>
            <div style={styles.infoIcon}>📖</div>
            <div>
              <h4>Total Subjects</h4>
              <p>{subjects.length} Core Subjects</p>
            </div>
          </div>
          <div style={styles.infoCard}>
            <div style={styles.infoIcon}>🎯</div>
            <div>
              <h4>Credits</h4>
              <p>{subjects.reduce((sum, sub) => sum + sub.credits, 0)} Total Credits</p>
            </div>
          </div>
          <div style={styles.infoCard}>
            <div style={styles.infoIcon}>📝</div>
            <div>
              <h4>Study Materials</h4>
              <p>{subjects.reduce((sum, sub) => sum + sub.materials, 0)}+ Files</p>
            </div>
          </div>
          <div style={styles.infoCard}>
            <div style={styles.infoIcon}>⭐</div>
            <div>
              <h4>Average Rating</h4>
              <p>
                {(
                  subjects.reduce((sum, sub) => sum + sub.rating, 0) / subjects.length
                ).toFixed(1)} / 5
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
  },
  header: {
    marginBottom: '2rem'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '0.5rem',
    fontSize: '1rem',
    fontWeight: '500',
    transition: 'all 0.3s',
    marginBottom: '1.5rem',
    '&:hover': {
      background: '#4338ca',
      transform: 'translateX(-5px)'
    }
  },
  pageHeader: {
    background: 'white',
    padding: '1.5rem 2rem',
    borderRadius: '15px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  courseSemesterInfo: {
    textAlign: 'center'
  },
  courseIcon: {
    fontSize: '2rem',
    marginRight: '0.5rem',
    verticalAlign: 'middle'
  },
  title: {
    fontSize: '2rem',
    marginBottom: '0.5rem',
